public ClassDescription defaultCaption()
{
    return "Action multi thread";
}

public static HDG_SysMultiThreadProcessController construct(SysOperationExecutionMode _executionMode = SysOperationExecutionMode::Synchronous)
{
    HDG_SysMultiThreadProcessController controller = new HDG_SysMultiThreadProcessController();
    controller.parmExecutionMode(_executionMode);
    return controller;
}

public static void main(Args _args)
{
    HDG_SysMultiThreadProcessController controller = HDG_SysMultiThreadProcessController::construct();
    controller.parmArgs(_args);
    controller.startOperation();
}
